import React, { useState, useEffect } from 'react';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import interactionPlugin from '@fullcalendar/interaction'; 
import axios from 'axios';

const Calendar = () => {
  const [events, setEvents] = useState([]);  // State to store events

  useEffect(() => {
    axios.get('http://127.0.0.1:3001/events')
      .then(response => {
        console.log(response.data);  // Check if data is being fetched
        const formattedEvents = response.data.map(event => ({
          id: event.id,
          title: event.title,  // Keep the title as it is
          start: new Date(event.start).toISOString(),
          description: event.description,
          url: event.url,
          flyerImage: event.flyerImage,
          extendedProps: {
            venue: event.venue  // Store the venue in extendedProps
          }
        }));
        setEvents(formattedEvents);
        console.log(formattedEvents);  // Log the formatted events
      })
      .catch(error => {
        console.error('Error fetching events:', error);
      });
  }, []);

  return (
    <FullCalendar
      plugins={[dayGridPlugin, interactionPlugin]}
      initialView="dayGridMonth"
      events={events}  // Pass the events to the calendar
      eventClick={(info) => {
        alert(info.event.venue);  // Debugging the click on event
      }}
    />
  );
};

export default Calendar;
